import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"프로젝트 만들기","description":"Fabric 템플릿 모드 생성기로 새 모드를 생성하는 방법에 대한 단계별 가이드입니다.","frontmatter":{"title":"프로젝트 만들기","description":"Fabric 템플릿 모드 생성기로 새 모드를 생성하는 방법에 대한 단계별 가이드입니다.","authors":["IMB11","Cactooz"],"files":[]},"headers":[],"relativePath":"ko_kr/1.21.1/develop/getting-started/creating-a-project.md","filePath":"versions/1.21.1/translated/ko_kr/develop/getting-started/creating-a-project.md","lastUpdated":1761424914000}`);var l={name:`ko_kr/1.21.1/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">프로젝트 만들기 <a class="header-anchor" href="#h1" aria-label="Permalink to “프로젝트 만들기”">​</a></h1><p>페브릭에는 템플릿 생성기를 사용하여 새 모드를 생성하는 쉬운 방법이 있습니다. 원하는 경우 예제 모드 저장소를 사용하여 수동으로 새 프로젝트를 생성할 수 있습니다. [수동으로 프로젝트 생성](#manual-project -creation).</p><h2 id="generating-a-project" tabindex="-1">프로젝트 생성하기 <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “프로젝트 생성하기”">​</a></h2><p><a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric 템플릿 모드 생성기</a>로 새 프로젝트를 생성할 수 있습니다. 모드 이름, 패키지 이름, 그리고 개발하려면 Minecraft 버전 등의 필수 항목을 입력해야 합니다.</p><p>패키지의 이름은 소문자여야 하며, 점으로 분류되고, 다른 프로그래머의 패키지와의 충돌을 피하기 위해 고유해야 합니다. 주로, <code>com.example.example-mod</code>같은 형식의 역순 인터넷 도메인으로 지정됩니다.</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="생성기 미리보기" loading="lazy"></p><p>만약 Kotlin을 사용하고 싶으면, Yarn 맵핑 보다는 Mojang의 공식 맵핑을 사용하거나, 데이터 생성기를 추가하고 싶은 경우, <code>고급 옵션</code>에서 적절한 옵션을 선택할 수 있습니다.</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="고급 옵션 섹션" loading="lazy"></p><p>필수 필드를 입력한 후 &#39;생성&#39; 버튼을 클릭하면 zip 파일 형식으로 새 프로젝트를 다운받을 수 있습니다.</p><p>압축파일을 원하는 위치에 푼다음 IntelliJ에서 열어줍니다.</p><p><img src="/assets/develop/getting-started/open-project.png" alt="프로젝트 열기 스크린샷" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">프로젝트 가져오기 <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “프로젝트 가져오기”">​</a></h2><p>IntelliJ IDEA에서 프로젝트를 열면, IDE가 자동으로 Gradle의 구성 요소를 불러온 다음 필요한 작업을 수행할 것입니다.</p><p>Gradle 빌드 알림을 받으면 <code>Import Gradle Project</code> 버튼을 눌러야 합니다.</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Gradle 확인 스크린샷" loading="lazy"></p><p>여기까지 하셨다면 프로젝트 탐색기에 프로젝트 파일이 뜨고 이제 모드 개발을 시작할 수 있습니다.</p><h2 id="manual-project-creation" tabindex="-1">직접 프로젝트 생성 <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “직접 프로젝트 생성”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>리포지토리를 복사하려면 <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a>이 설치되어 있어야 합니다.</p></div><p>Fabric 템플릿 모드 생성기를 사용할 수 없는 경우 다음 단계에 따라 프로젝트를 수동으로 생성할 수 있습니다.</p><p>먼저 Git을 이용해 리포지토리를 복사해 줍니다.</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>명령어를 실행하면 my-mod-project라는 새 폴더에 복사됩니다.</p><p>새로 생성된 폴더에서 <code>.git</code> 폴더를 삭제후 Intellij에서 열어줍니다. 만약 파일 탐색에서 <code>.git</code> 폴더가 안보인다면 파일 탐색기 설정에서 숨긴 항목 표시를 켜줍니다.</p><p>IntelliJ에서 프로젝트를 열면 에디터가 자동으로 필요한 작업을 실행합니다.</p><p>앞에서 말한 것처럼 Gradle 빌드 알림을 받으면 <code>Import Gradle Project</code> 버튼을 눌러줍니다.</p><h3 id="modifying-the-template" tabindex="-1">템플릿 수정하기 <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “템플릿 수정하기”">​</a></h3><p>프로젝트를 가져온 후에는 모드 세부정보를 수정해야 합니다.</p><ul><li>프로젝트의 <code>gradle.properties</code> 파일을 수정해 <code>maven_group</code> 및 <code>archive_base_name</code> 속성을 모드와 일치하도록 변경하세요.</li><li><code>fabric.mod.json</code> 파일을 수정하여 <code>id</code>, <code>name</code> 및 <code>description</code> 속성을 모드와 일치하도록 변경하세요.</li><li>대상으로 삼으려는 버전과 일치하게 <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a>을(를) 통해 쿼리할 수 있는 Minecraft의 버전과 맵핑, 로더와 Loom 버전을 업데이트 해주세요.</li></ul><p>모드와 패키지 이름이 일치하도록 패키지 이름과 모드의 메인 클래스 이름을 변경할 수 있습니다.</p>`,29)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};